-- VIEW VW_LOCADORA (mapeado para produtos)
DROP VIEW IF EXISTS vw_locadora;
CREATE VIEW vw_locadora AS
SELECT p.nome AS titulo,
       p.categoria AS genero,
       p.quantidade AS quantidade_disponivel,
       ROUND(p.preco_Unitario, 2) AS valor_diaria,
       ROUND(p.quantidade * p.preco_Unitario, 2) AS valor_total_estoque
FROM produtos p;